                    string tt = string(buf, p);

                    mmset[t].push_back(tt);

//                     cout<<"found: "<<tt<<endl;

                    p = 0;

                } else {

                    buf[p++] = inc;

                }

            }

        }

        queue< string >workingset;

        workingset.push(fst);

        while(!workingset.empty()){

            string pivot = workingset.front(); workingset.pop();

            if(visited[pivot])continue;

            if(mmset.find(pivot)==mmset.end()){

                res.insert(pivot);

