            } else {

                for(auto i = mmset[pivot].begin(); i!=mmset[pivot].end(); i++){

                    workingset.push(*i);

                }

                visited[pivot] = true;

            }

        }

        printf("%d\n",res.size());

    }

    return 0;

}

