using namespace std;



map<string, set<string>> res;

set<string> te;

map<string, int> OK;



set<string> dfs(const string& s) {

	if (OK[s]) {

		return res[s];

	}

	OK[s] = 1;

	auto tmp = res[s];

	for (auto t : tmp) {

		if (te.count(t) == 0) {

			continue;

		}

		res[s].erase(t);

		auto ss = dfs(t);

		res[s].insert(ss.begin(), ss.end());

	}

	return res[s];

}



int main()

{

	int n;

	while (cin >> n, n) {

		string S;

		vector<string> t(n);

		for(int j = 0;j < n;j++) {

			cin >> S;

			int tmp = 0;

			for (int i = 0; i < (int)S.size(); i++) {

				if (S[i] == ':') {

					te.insert(S.substr(0, i));

					t[j] = S.substr(0, i);

					tmp = i + 1;

				}

				else if (S[i] == ',' || S[i] == '.') {

					res[t[j]].insert(S.substr(tmp, i - tmp));

					tmp = i + 1;

				}

			}

		}

		cout << dfs(t[0]).size() << endl;

		res.clear();

		te.clear();

		OK.clear();

	}

	return 0;

}

