set<string> ans;

void dfs(int u, map<string, int>& dic, vector<vector<string> >& graph)

{

    vis[u] = true;



    for(int i=0; i<graph[u].size(); i++) {

        string n = graph[u][i];

        if(dic.count(n)) {

