    ID.clear();

    for(int i = 1; i <= n; i++) {

        time_stamp[i].clear();

    }

}

int tranTime(int hh, int mm) {

    return hh * 60 + mm;

}

int godness;



int Cut(int l, int r, int a, int b) {

    int ret = 0;

    if(r <= a || l >= b) {

        return 0;

    }

    return min(b, r) - max(l, a);

}

