    if(godness == -1) {

        return ;

    }

    for(int i = 1; i <= tot; i++) {

        if(i == godness) {

            continue;

        }

        int st = 0, ed;

        for(int j = 0; j < (int)time_stamp[i].size(); j += 2) {

            int l, r;

            l = time_stamp[i][j].when;

            r = time_stamp[i][j + 1].when;

            while(st < (int)time_stamp[godness].size() && time_stamp[godness][st + 1].when <= l) {

                st += 2;

            }

            for(int k = st; k < (int)time_stamp[godness].size(); k += 2) {

                sum[i] += Cut(l, r, time_stamp[godness][k].when, time_stamp[godness][k + 1].when);

                if(time_stamp[godness][k].when >= r) {

                    break;

                }

            }

        }

        ans = max(ans, sum[i]);

    }



}

