            time_stamp[dict[id]].push_back(  Point(tranTime(hh, mm))  );

        } else {

            Solve();

            for(int i = 1; i <= tot; i++) {

                time_stamp[i].clear();

            }

            time_stamp[dict[id]].push_back(  Point(tranTime(hh, mm))  );

        }

        lastDay = day;

        lastMonth = month;    

    }

    Solve();

}

